package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Field;
import java.util.ArrayList;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class JsonArrayTest {

  private JsonArray jsonArray;

  @BeforeEach
  void setUp() {
    jsonArray = new JsonArray();
  }

  @Test
  void add_withNonNullElement_addsElementToList() throws Exception {
    JsonElement element = mock(JsonElement.class);

    jsonArray.add(element);

    ArrayList<JsonElement> elements = getElementsList(jsonArray);
    assertEquals(1, elements.size());
    assertSame(element, elements.get(0));
  }

  @Test
  void add_withNullElement_addsJsonNullInstance() throws Exception {
    jsonArray.add(null);

    ArrayList<JsonElement> elements = getElementsList(jsonArray);
    assertEquals(1, elements.size());
    assertSame(JsonNull.INSTANCE, elements.get(0));
  }

  @SuppressWarnings("unchecked")
  private ArrayList<JsonElement> getElementsList(JsonArray jsonArray) throws Exception {
    Field elementsField = JsonArray.class.getDeclaredField("elements");
    elementsField.setAccessible(true);
    return (ArrayList<JsonElement>) elementsField.get(jsonArray);
  }
}
